import { axios, store } from './config/axios-config'

const getIndicadores = async ({anoSelecionado, codOcupacoes, estadoSelecionado, municipioSelecionado, cursoSelecionado}) => {


    if(anoSelecionado !== '' && codOcupacoes.length > 0 && estadoSelecionado !== ''){
        
        // Bug do Redux. Tem que adicionar esse setTimeout pra funcionar
        setTimeout(() =>{store.dispatch({ type: 'SET_LOADING', loading: true })}, 0)
        
        
        const response = await axios.post('/getIndicadores', {
            ano: anoSelecionado,
            ocupacoes: codOcupacoes,
            uf: estadoSelecionado,
            municipio: municipioSelecionado,
            curso: cursoSelecionado
        })
        

        store.dispatch({ type: 'SET_INDICADORES', list: response.data })
    }

}

export default getIndicadores