import { axios, store } from './config/axios-config'

const getOcupationData = async (curso) => {

    const response = await axios.post('/ocupacoes', curso)

    store.dispatch({ type: 'SET_OCUPATION', ocupacoes: response.data.ocupacoes  })
    store.dispatch({ type: 'GET_LIST_OCUPATIONS', list: response.data.listaOcupacoes  })


}

export default getOcupationData